import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"文档站维护说明","description":"","frontmatter":{},"headers":[],"relativePath":"site-maintenance.md","filePath":"site-maintenance.md","lastUpdated":1783267649000}'),d={name:"site-maintenance.md"};function o(l,e,n,c,p,h){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="文档站维护说明" tabindex="-1">文档站维护说明 <a class="header-anchor" href="#文档站维护说明" aria-label="Permalink to &quot;文档站维护说明&quot;">​</a></h1><p>PaperSeek 文档站使用 VitePress 构建。文档源码和发布产物分开管理：</p><table tabindex="0"><thead><tr><th>分支</th><th>用途</th></tr></thead><tbody><tr><td><code>main</code></td><td>社区开发分支。保存源码、Python 包、测试、README、<code>docs/</code> 文档源码和 VitePress 配置。</td></tr><tr><td><code>gh-pages</code></td><td>GitHub Pages 静态发布分支。只保存构建后的站点产物，不作为开发分支。</td></tr></tbody></table><h2 id="贡献路径" tabindex="-1">贡献路径 <a class="header-anchor" href="#贡献路径" aria-label="Permalink to &quot;贡献路径&quot;">​</a></h2><p>社区贡献应提交到 <code>main</code>：</p><ul><li>修改 <code>README.md</code>、<code>README.en.md</code>。</li><li>修改 <code>docs/</code> 下的用户手册、在线体验说明、部署指南和文档站配置。</li><li>通过 Pull Request 触发 Python CI 和文档构建检查。</li></ul><p>不要直接向 <code>gh-pages</code> 提交社区文档源码。<code>gh-pages</code> 的内容由 GitHub Actions 生成。</p><h2 id="发布规则" tabindex="-1">发布规则 <a class="header-anchor" href="#发布规则" aria-label="Permalink to &quot;发布规则&quot;">​</a></h2><p><code>.github/workflows/docs.yml</code> 在以下文件变化时运行：</p><ul><li><code>docs/**</code></li><li><code>README.md</code></li><li><code>README.en.md</code></li><li><code>package.json</code></li><li><code>package-lock.json</code></li><li><code>.github/workflows/docs.yml</code></li></ul><p>Pull Request 只构建文档站，不发布。推送到 <code>main</code> 后，工作流会把 <code>docs/.vitepress/dist</code> 发布到 <code>gh-pages</code>。</p><h2 id="pypi-发布" tabindex="-1">PyPI 发布 <a class="header-anchor" href="#pypi-发布" aria-label="Permalink to &quot;PyPI 发布&quot;">​</a></h2><p>PaperSeek 的 Python 包通过 <code>.github/workflows/publish-pypi.yml</code> 发布到 PyPI。该工作流会：</p><ol><li>在 Python 3.12 上构建 wheel 和 sdist。</li><li>使用 <code>twine check</code> 校验发布产物。</li><li>通过 <code>pypa/gh-action-pypi-publish</code> 上传到 PyPI。</li></ol><p>触发方式：</p><ul><li>发布 GitHub Release 时自动触发。</li><li>在 GitHub Actions 页面手动运行 <code>Publish Python package to PyPI</code>。</li></ul><p>仓库需要配置 secret：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PYPI_API_TOKEN</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>该值应使用 PyPI project-scoped API token，格式通常以 <code>pypi-</code> 开头。不要把 PyPI token 写入 <code>.env.example</code>、README、文档或 issue。</p><p>发布前需要先更新：</p><ul><li><code>pyproject.toml</code> 中的 <code>project.version</code></li><li><code>paperseek/__init__.py</code> 中的 <code>__version__</code></li></ul><p>PyPI 不允许覆盖同一版本号。若上传失败提示文件已存在，应升高版本号后重新构建发布。</p><h2 id="gh-pages-分支约束" tabindex="-1">gh-pages 分支约束 <a class="header-anchor" href="#gh-pages-分支约束" aria-label="Permalink to &quot;gh-pages 分支约束&quot;">​</a></h2><p><code>gh-pages</code> 分支应满足：</p><ul><li>只存静态发布产物。</li><li>根目录包含生成分支说明 <code>README.md</code>。</li><li>不发 Python 包，不运行 Python 发布流程。</li><li>不保存任何 secret、token、API Key 或本地配置。</li><li>默认不接受人工 PR，除非需要紧急修复发布产物。</li></ul><p>如果仓库启用了分支保护，需要允许 <code>github-actions[bot]</code> 或 GitHub Actions 使用 <code>GITHUB_TOKEN</code> 写入 <code>gh-pages</code>，否则自动部署会被规则拦截。</p><h2 id="本地预览" tabindex="-1">本地预览 <a class="header-anchor" href="#本地预览" aria-label="Permalink to &quot;本地预览&quot;">​</a></h2><p>安装依赖：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>启动本地文档站：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>构建静态站点：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',33)])])}const b=a(d,[["render",o]]);export{u as __pageData,b as default};
